public class SortByString {
  public static void main( String[] args ) {
    // define clause
    List<Document> shouldClause =
        List.of(
            new Document(
                "wildcard",
                new Document("query", "Prance*")
                    .append("path", "title")
                    .append("allowAnalyzedField", true)),
            new Document(
                "wildcard",
                new Document("query", "Prince*")
                    .append("path", "title")
                    .append("allowAnalyzedField", true)));

    // define query
    Document agg =
        new Document(
            "$search",
            new Document("index", "default")
            .append("compound",
                new Document("should", shouldClause))
                .append("sort", new Document("title", 1L)));

    // specify connection
    String uri = "<connection-string>";

    // establish connection and set namespace
    try (MongoClient mongoClient = MongoClients.create(uri)) {
      MongoDatabase database = mongoClient.getDatabase("sample_mflix");
      MongoCollection<Document> collection = database.getCollection("movies");

      // run query and print results
      collection.aggregate(Arrays.asList(agg, 
        limit(5),
        project(fields(excludeId(), include("title"), computed("score", new Document("$meta", "searchScore"))))))
        .forEach(doc -> System.out.println(doc.toJson()));	
    }
  }
}

import com.mongodb.client.model.Aggregates.limit
import com.mongodb.client.model.Aggregates.project
import com.mongodb.client.model.Projections.*
import com.mongodb.kotlin.client.coroutine.MongoClient
import kotlinx.coroutines.runBlocking
import org.bson.Document

fun main() {
    // establish connection and set namespace
    val uri = "<connection-string>"
    val mongoClient = MongoClient.create(uri)
    val database = mongoClient.getDatabase("sample_mflix")
    val collection = database.getCollection<Document>("movies")

    runBlocking {
        // define clause
        val shouldClause = listOf(
            Document("wildcard", Document("query", "Prance*")
                .append("path", "title")
                .append("allowAnalyzedField", true)),
            Document("wildcard", Document("query", "Prince*")
                .append("path", "title")
                .append("allowAnalyzedField", true))
        )

        // define query
        val agg = Document(
            "\$search",
            Document("index", "default")
                .append(
                    "compound",
                    Document("should", shouldClause)
                )
                .append("sort", Document("title", 1L))
        )

        // run query and print results
        val resultsFlow = collection.aggregate<Document>(
            listOf(
                agg,
                limit(5),
                project(fields(
                    excludeId(),
                    include("title"),
                    computed("score", Document("\$meta", "searchScore"))
                ))
            )
        )
        resultsFlow.collect { println(it) }
    }
    mongoClient.close()
}

